22→export function buildEntityDetailResponse(
23→  detail: EntityDetail,
24→  agentSessionRow?: AgentSessionRow,
25→): EntityDetailResponse {
26→  const response: EntityDetailResponse = {
27→    entity: detail.entity,
28→    relationships: detail.relationships,
