  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { HttpError } from "../http/errors";
  3→import { logError, logInfo } from "../http/observability";
  4→import { jsonError, jsonResponse } from "../http/response";
  5→import type { ServerDependencies } from "../runtime/types";
  6→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  7→import {
  8→  getEntityDetail,
  9→  parseRecordIdString,
 10→  type GraphEntityTable,
 11→} from "../graph/queries";
 12→import { buildEntityDetailResponse, type AgentSessionRow } from "./entity-detail-response";
 13→
 14→export function createEntityDetailHandler(
 15→  deps: ServerDependencies,
 16→): (entityId: string, url: URL) => Promise<Response> {
 17→  return (entityId: string, url: URL) => handleEntityDetail(deps, entityId, url);
 18→}
 19→
 20→async function handleEntityDetail(
 21→  deps: ServerDependencies,
 22→  entityId: string,
 23→  url: URL,
 24→): Promise<Response> {
 25→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 26→  if (!workspaceId) {
 27→    return jsonError("workspaceId is required", 400);
 28→  }
 29→
 30→  let workspaceRecord;
 31→  try {
 32→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 33→  } catch (error) {
 34→    if (error instanceof HttpError) {
 35→      return jsonError(error.message, error.status);
 36→    }
 37→    logError("entity.detail.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 38→    return jsonError("failed to resolve workspace", 500);
 39→  }
 40→
 41→  try {
 42→    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "suggestion"];
 43→    const entityRecord = parseRecordIdString(entityId, entityTables);
 44→    const detail = await getEntityDetail({
 45→      surreal: deps.surreal,
 46→      workspaceRecord,
 47→      entityRecord,
 48→    });
 49→
 50→    const agentSessionRow = detail.entity.kind === "task"
 51→      ? await findActiveAgentSession(deps.surreal, entityRecord)
 52→      : undefined;
 53→
 54→    const response = buildEntityDetailResponse(detail, agentSessionRow);
 55→
 56→    logInfo("entity.detail.served", "Entity detail served", {
 57→      workspaceId,
 58→      entityId,
 59→      relationshipCount: detail.relationships.length,
 60→      provenanceCount: detail.provenance.length,
 61→      hasAgentSession: !!agentSessionRow,
 62→    });
 63→
 64→    return jsonResponse(response, 200);
 65→  } catch (error) {
 66→    logError("entity.detail.failed", "Entity detail failed", error, {
 67→      workspaceId,
 68→      entityId,
 69→    });
 70→    const message = error instanceof Error ? error.message : "entity detail failed";
 71→    return jsonError(message, 500);
 72→  }
 73→}
 74→
 75→const ACTIVE_SESSION_STATUSES = ["spawning", "active", "idle"];
 76→
 77→type AgentSessionQueryRow = {
 78→  id: RecordId<"agent_session", string>;
 79→  orchestrator_status: string;
 80→  stream_id: string;
 81→  started_at: string | Date;
 82→  files_changed: Array<unknown> | undefined;
 83→};
 84→
 85→async function findActiveAgentSession(
 86→  surreal: Surreal,
 87→  taskRecord: RecordId<string, string>,
 88→): Promise<AgentSessionRow | undefined> {
 89→  const [rows] = await surreal
 90→    .query<[AgentSessionQueryRow[]]>(
 91→      [
 92→        "SELECT id, orchestrator_status, stream_id, started_at, files_changed",
 93→        "FROM agent_session",
 94→        "WHERE task_id = $taskRecord",
 95→        "AND orchestrator_status IN $statuses",
 96→        "ORDER BY started_at DESC",
 97→        "LIMIT 1;",
 98→      ].join(" "),
 99→      { taskRecord, statuses: ACTIVE_SESSION_STATUSES },
100→    )
101→    .collect<[AgentSessionQueryRow[]]>();
102→
103→  const row = rows[0];
104→  if (!row) return undefined;
105→
106→  const startedAt = row.started_at instanceof Date
107→    ? row.started_at.toISOString()
108→    : row.started_at;
109→
110→  return {
111→    id: row.id.id as string,
112→    orchestrator_status: row.orchestrator_status,
113→    stream_id: row.stream_id ?? "",
114→    started_at: startedAt,
115→    files_changed_count: row.files_changed?.length ?? 0,
116→  };
117→}
