  8→import { RelationshipList } from "./RelationshipList";
  9→import { ProvenanceSection } from "./ProvenanceSection";
 10→import { AgentStatusSection } from "./AgentStatusSection";
 11→import { useViewState } from "../../stores/view-state";
 12→import { acceptSuggestion, confirmDecision, convertSuggestion, deferSuggestion, dismissSuggestion, markTaskComplete, overrideDecision, setEntityPriority } from "../../graph/actions";
 13→
 14→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 15→
 16→const CATEGORY_TO_ENTITY_TYPE: Record<string, "task" | "feature" | "decision" | "project"> = {
 17→  optimization: "task",
 18→  risk: "decision",
 19→  opportunity: "feature",
 20→  conflict: "decision",
 21→  missing: "task",
 22→  pivot: "project",
 23→};
 24→
 25→export function EntityDetailPanel({
 26→  entityId,
 27→  workspaceId,
 28→  onClose,
 29→  onEntityClick,
 30→}: {
 31→  entityId: string;
 32→  workspaceId: string;
 33→  onClose: () => void;
 34→  onEntityClick: (entityId: string) => void;
 35→}) {
 36→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 37→  const [loading, setLoading] = useState(true);
 38→  const [error, setError] = useState<string | undefined>();
 39→  const [actionPending, setActionPending] = useState(false);
 40→  const [showConvertForm, setShowConvertForm] = useState(false);
 41→  const [convertKind, setConvertKind] = useState<"task" | "feature" | "decision" | "project">("task");
 42→  const [convertTitle, setConvertTitle] = useState("");
 43→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
 44→  const navigate = useNavigate();
 45→
 46→  useEffect(() => {
 47→    setLoading(true);
 48→    setError(undefined);
 49→
 50→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 51→      .then(async (response) => {
 52→        if (!response.ok) {
 53→          const body = await response.text();
 54→          throw new Error(body);
 55→        }
 56→        return response.json() as Promise<EntityDetailResponse>;
 57→      })
 58→      .then((data) => {
 59→        setDetail(data);
 60→        setLoading(false);
 61→      })
 62→      .catch((err) => {
 63→        setError(err instanceof Error ? err.message : "Failed to load entity");
 64→        setLoading(false);
 65→      });
 66→  }, [entityId, workspaceId]);
 67→
 68→  function handleJumpToMessage(messageId: string, conversationId?: string) {
 69→    if (conversationId) {
 70→      void navigate({ to: "/chat/$conversationId", params: { conversationId }, search: { message: messageId } });
 71→    } else {
 72→      void navigate({ to: "/chat", search: { message: messageId } });
 73→    }
 74→  }
 75→
 76→  async function handleConfirm() {
 77→    if (!detail || actionPending) return;
 78→    setActionPending(true);
 79→    try {
 80→      await confirmDecision(workspaceId, entityId);
 81→      setDetail((prev) =>
 82→        prev
 83→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 84→          : prev,
 85→      );
 86→    } finally {
 87→      setActionPending(false);
 88→    }
 89→  }
 90→
 91→  async function handleOverride() {
 92→    if (!detail || actionPending) return;
 93→    const newSummary = window.prompt("New decision summary:");
 94→    if (!newSummary) return;
 95→    setActionPending(true);
 96→    try {
 97→      await overrideDecision(workspaceId, entityId, newSummary);
 98→      setDetail((prev) =>
 99→        prev
100→          ? {
101→              ...prev,
102→              entity: {
103→                ...prev.entity,
104→                name: newSummary,
105→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
106→              },
107→            }
108→          : prev,
109→      );
110→    } finally {
111→      setActionPending(false);
112→    }
113→  }
114→
115→  async function handleComplete() {
116→    if (!detail || actionPending) return;
117→    setActionPending(true);
118→    try {
119→      await markTaskComplete(workspaceId, entityId);
120→      setDetail((prev) =>
121→        prev
122→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
123→          : prev,
124→      );
125→    } finally {
126→      setActionPending(false);
127→    }
128→  }
129→
130→  if (loading) {
131→    return (
132→      <aside className="entity-detail-panel">
133→        <p className="entity-detail-meta">Loading...</p>
134→      </aside>
135→    );
136→  }
137→
138→  if (error || !detail) {
139→    return (
140→      <aside className="entity-detail-panel">
141→        <div className="entity-detail-header">
142→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
143→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
144→        </div>
145→      </aside>
146→    );
147→  }
148→
149→  const kind = detail.entity.kind as EntityKind;
150→  const status = (detail.entity.data.status as string | undefined) ?? "";
151→  const rationale = detail.entity.data.rationale as string | undefined;
152→
153→  async function handleSuggestionAction(
154→    action: (workspaceId: string, entityId: string) => Promise<unknown>,
155→    resultStatus: string,
156→  ) {
157→    if (actionPending) return;
158→    setActionPending(true);
159→    try {
160→      await action(workspaceId, entityId);
161→      setDetail((prev) =>
162→        prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: resultStatus } } } : prev,
163→      );
164→    } finally {
165→      setActionPending(false);
166→    }
167→  }
168→
169→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
170→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
171→  const showComplete = kind === "task" && status !== "done";
172→  const showSuggestionActions = kind === "suggestion" && (status === "pending" || status === "deferred");
173→
174→  return (
175→    <aside className="entity-detail-panel">
176→      <div className="entity-detail-header">
177→        <div>
178→          <EntityBadge kind={kind} />
179→          <h3>{detail.entity.name}</h3>
180→        </div>
181→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
182→      </div>
183→
184→      <div className="entity-detail-section">
185→        <h4>Metadata</h4>
186→        <dl className="entity-detail-meta">
187→          {status ? (
188→            <>
189→              <dt>Status</dt>
190→              <dd>{status}</dd>
191→            </>
192→          ) : undefined}
193→          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
194→            <>
195→              <dt>Category</dt>
196→              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
197→            </>
198→          ) : undefined}
199→          {detail.entity.data.confidence !== undefined ? (
200→            <>
201→              <dt>Confidence</dt>
202→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
203→            </>
204→          ) : undefined}
205→          {detail.entity.data.created_at ? (
206→            <>
207→              <dt>Created</dt>
208→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
209→            </>
210→          ) : undefined}
211→          {detail.entity.data.owner_name ? (
212→            <>
213→              <dt>Owner</dt>
214→              <dd>{detail.entity.data.owner_name as string}</dd>
215→            </>
216→          ) : undefined}
217→          {(kind === "task" || kind === "decision" || kind === "question") ? (
218→            <>
219→              <dt>Priority</dt>
220→              <dd>
221→                <select
222→                  value={(detail.entity.data.priority as string | undefined) ?? ""}
223→                  disabled={actionPending}
224→                  onChange={async (e) => {
225→                    const value = e.target.value as EntityPriority;
226→                    if (!value) return;
227→                    setActionPending(true);
228→                    try {
229→                      await setEntityPriority(workspaceId, entityId, value);
230→                      setDetail((prev) =>
231→                        prev
232→                          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, priority: value } } }
233→                          : prev,
234→                      );
235→                    } finally {
236→                      setActionPending(false);
237→                    }
238→                  }}
239→                >
240→                  <option value="" disabled>—</option>
241→                  {ENTITY_PRIORITIES.map((p) => (
242→                    <option key={p} value={p}>{p}</option>
243→                  ))}
244→                </select>
245→              </dd>
246→            </>
247→          ) : undefined}
248→        </dl>
249→      </div>
250→
251→      {kind === "task" ? (
252→        <AgentStatusSection
253→          entityId={entityId}
254→          workspaceId={workspaceId}
255→          entityKind={kind}
256→          entityStatus={status}
257→          agentSession={detail.agentSession}
258→        />
259→      ) : undefined}
260→
261→      <DescriptionSection data={detail.entity.data} kind={kind} onEntityClick={onEntityClick} />
262→
263→      {rationale ? (
264→        <div className="entity-detail-section">
265→          <h4>Rationale</h4>
266→          <p className="entity-detail-meta">{rationale}</p>
267→        </div>
268→      ) : undefined}
269→
270→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
271→
272→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
273→
274→      <div className="entity-detail-actions">
275→        <button
276→          type="button"
277→          onClick={() => {
278→            navigateToDiscussEntity({
279→              id: entityId,
280→              kind,
281→              name: detail.entity.name,
282→              ...(status ? { status } : {}),
283→            });
284→            void navigate({ to: "/chat" });
285→          }}
286→        >
287→          Discuss
288→        </button>
289→        {showConfirm ? (
290→          <button type="button" disabled={actionPending} onClick={handleConfirm}>
291→            Confirm
292→          </button>
293→        ) : undefined}
294→        {showOverride ? (
295→          <button type="button" disabled={actionPending} onClick={handleOverride}>
296→            Override
297→          </button>
298→        ) : undefined}
299→        {showComplete ? (
300→          <button type="button" disabled={actionPending} onClick={handleComplete}>
301→            Mark Complete
302→          </button>
303→        ) : undefined}
304→        {showSuggestionActions ? (
305→          <>
306→            <button type="button" disabled={actionPending} onClick={() => handleSuggestionAction(acceptSuggestion, "accepted")}>Accept</button>
307→            <button type="button" disabled={actionPending} onClick={() => {
308→              const category = (detail.entity.data.category as string) ?? "";
309→              setConvertKind(CATEGORY_TO_ENTITY_TYPE[category] ?? "task");
310→              setConvertTitle(detail.entity.name);
311→              setShowConvertForm(true);
312→            }}>Convert</button>
313→            <button type="button" disabled={actionPending} onClick={() => handleSuggestionAction(deferSuggestion, "deferred")}>Defer</button>
314→            <button type="button" disabled={actionPending} onClick={() => handleSuggestionAction(dismissSuggestion, "dismissed")}>Dismiss</button>
315→          </>
316→        ) : undefined}
317→        {showConvertForm ? (
318→          <div className="entity-convert-form">
319→            <label>
320→              Convert to:
321→              <select value={convertKind} onChange={(e) => setConvertKind(e.target.value as typeof convertKind)}>
322→                <option value="task">Task</option>
323→                <option value="feature">Feature</option>
324→                <option value="decision">Decision</option>
325→                <option value="project">Project</option>
326→              </select>
327→            </label>
328→            <label>
329→              Title:
330→              <input type="text" value={convertTitle} onChange={(e) => setConvertTitle(e.target.value)} />
331→            </label>
332→            <div className="entity-convert-form-actions">
333→              <button type="button" disabled={actionPending || !convertTitle.trim()} onClick={async () => {
334→                setActionPending(true);
335→                try {
336→                  await convertSuggestion(workspaceId, entityId, convertKind, convertTitle.trim() || undefined);
337→                  setDetail((prev) => prev ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "converted" } } } : prev);
338→                  setShowConvertForm(false);
339→                } finally { setActionPending(false); }
340→              }}>Confirm</button>
341→              <button type="button" onClick={() => setShowConvertForm(false)}>Cancel</button>
342→            </div>
343→          </div>
344→        ) : undefined}
345→      </div>
346→    </aside>
347→  );
348→}
