 1→import type { EntityActionRequest, EntityPriority } from "../../shared/contracts";
 2→
 3→async function executeAction(workspaceId: string, entityId: string, body: EntityActionRequest): Promise<void> {
 4→  const response = await fetch(
 5→    `/api/entities/${encodeURIComponent(entityId)}/actions?workspaceId=${encodeURIComponent(workspaceId)}`,
 6→    {
 7→      method: "POST",
 8→      headers: { "Content-Type": "application/json" },
 9→      body: JSON.stringify(body),
10→    },
11→  );
12→
13→  if (!response.ok) {
14→    const text = await response.text();
15→    throw new Error(text);
16→  }
17→}
18→
19→export function confirmDecision(workspaceId: string, decisionId: string, notes?: string): Promise<void> {
20→  return executeAction(workspaceId, decisionId, { action: "confirm", notes });
21→}
22→
23→export function overrideDecision(workspaceId: string, decisionId: string, newSummary: string, notes?: string): Promise<void> {
24→  return executeAction(workspaceId, decisionId, { action: "override", newSummary, notes });
25→}
26→
27→export function markTaskComplete(workspaceId: string, taskId: string): Promise<void> {
28→  return executeAction(workspaceId, taskId, { action: "complete" });
29→}
30→
31→export function acceptSuggestion(workspaceId: string, suggestionId: string): Promise<void> {
32→  return executeAction(workspaceId, suggestionId, { action: "accept" });
33→}
34→
35→export function dismissSuggestion(workspaceId: string, suggestionId: string): Promise<void> {
36→  return executeAction(workspaceId, suggestionId, { action: "dismiss" });
37→}
38→
39→export function deferSuggestion(workspaceId: string, suggestionId: string): Promise<void> {
40→  return executeAction(workspaceId, suggestionId, { action: "defer" });
41→}
42→
43→export function setEntityPriority(workspaceId: string, entityId: string, priority: EntityPriority): Promise<void> {
44→  return executeAction(workspaceId, entityId, { action: "set_priority", priority });
45→}
46→
47→export function convertSuggestion(
48→  workspaceId: string,
49→  suggestionId: string,
50→  convertTo: "task" | "feature" | "decision" | "project",
51→  convertTitle?: string,
52→): Promise<void> {
53→  return executeAction(workspaceId, suggestionId, {
54→    action: "convert",
55→    convertTo,
56→    ...(convertTitle ? { convertTitle } : {}),
57→  });
58→}
