 20→  orchestratorStatus: string;
 21→  worktreeBranch?: string;
 22→  startedAt: string;
 23→  lastEventAt?: string;
 24→};
 25→
 26→export type SessionReviewResponse = {
 27→  agentSessionId: string;
 28→  taskId: string;
 29→  taskTitle: string;
 30→  summary?: string;
 31→  diff: {
 32→    files: Array<{
 33→      path: string;
 34→      status: "added" | "modified" | "deleted";
 35→      additions: number;
 36→      deletions: number;
 37→    }>;
 38→    rawDiff: string;
 39→    stats: {
